+fn synthetic_tool_arg_value(type_name: Option<&str>) -> Value {
+    match type_name {
+        Some("number" | "integer") => json!(2),
+        Some("boolean") => json!(true),
+        Some("array") => json!([]),
+        Some("object") => json!({}),
+        _ => json!("verification test"),
+    }
